import { G, T, A, O, P } from './domains.js';

export const part3 = [
  {id:253,domain:P,question:"What is a security operations center (SOC)?",options:["A team monitoring threats 24/7","An internal compliance audit team","A physical server room","A cloud vulnerability management app"],answer:0,explanation:"A SOC combines people, processes, and technology to continuously monitor, detect, analyze, and respond to security threats.",optionExplanations:["A SOC continuously monitors, detects, and responds to threats.","Compliance audits review regulations periodically, not run 24/7 ops.","A data center is the server room; a SOC is a security function.","A vulnerability app tracks patching, not around-the-clock monitoring."]},
  {id:254,domain:G,question:"Which of the following describes the concept of tokenization in data security?",options:["Reversible AES encryption of data fields","Replacing data with a vault-mapped token","One-way SHA-256 hashing of data","Splitting records across multiple servers"],answer:1,explanation:"Tokenization replaces sensitive data (like credit card numbers) with non-sensitive tokens; the mapping is in a secure token vault.",optionExplanations:["Encryption is reversible with a key; tokens have no math link to the original.","Tokenization swaps data for a random token stored in a secure vault.","Hashing is one-way; tokens can be mapped back via the vault.","Splitting data across servers is sharding, not tokenization."]},
  {id:255,domain:G,question:"What is the purpose of FIDO2 / WebAuthn?",options:["Passwordless auth with keys or biometrics","Encrypting web browsing sessions","Managing certificate issuance and revocation","Encrypted email communication"],answer:0,explanation:"FIDO2/WebAuthn enables strong authentication via hardware security keys (YubiKey) or device biometrics, eliminating passwords.",optionExplanations:["FIDO2 enables strong authentication via hardware keys or biometrics.","TLS/HTTPS encrypts sessions; FIDO2 handles authentication.","Certificate lifecycle is a PKI function, not FIDO2's role.","Email encryption is S/MIME or PGP, unrelated to FIDO2."]},
  {id:256,domain:T,question:"What is a RAT (Remote Access Trojan)?",options:["A sanctioned IT remote admin tool","A vulnerability in RDP software","Malware for hidden remote control","A firewall bypass technique"],answer:2,explanation:"RATs silently install themselves and give attackers full remote control including file access, webcam, microphone, and keylogging.",optionExplanations:["Legit remote tools are authorized and visible, unlike a RAT.","RDP vulnerabilities are CVEs, a different concept from RAT malware.","A RAT covertly gives attackers persistent remote control.","Firewall bypass is a separate technique from RAT malware itself."]},
  {id:257,domain:T,question:"What is a pass-the-hash attack?",options:["Repeating the same request","Authenticating with a stolen hash, no password needed","Cracking MD5 hashes with rainbow tables","Sharing one bcrypt hash across accounts"],answer:1,explanation:"Pass-the-hash exploits Windows NTLM: an attacker captures the hash and uses it directly to authenticate, bypassing the need for plaintext.",optionExplanations:["Repeating requests describes a replay attack, not pass-the-hash.","Pass-the-hash uses a captured NTLM hash directly to authenticate.","Rainbow tables crack hashes; pass-the-hash reuses the hash directly.","Sharing a hash across accounts is a provisioning issue, not this attack."]},
  {id:258,domain:T,question:"What is privilege escalation?",options:["Issuing time-limited admin credentials","Gaining higher access than granted","Enrolling staff in certification courses","Raising an incident's priority level"],answer:1,explanation:"Privilege escalation exploits vulnerabilities or misconfigurations to obtain higher privileges, such as gaining admin from a standard user account.",optionExplanations:["Temporary admin access is authorized provisioning, not escalation.","Privilege escalation exploits flaws to gain unauthorized higher access.","Training is HR development, unrelated to privilege escalation.","Raising incident priority is an IR process step, not an attack."]},
  {id:259,domain:T,question:"Which of the following is a characteristic of a polymorphic virus?",options:["Self-replicating with no host file","Encrypting files for ransom","Infecting only one file type","Mutating its code each infection"],answer:3,explanation:"Polymorphic malware mutates its code each replication cycle, making signature-based detection very difficult.",optionExplanations:["No host file describes a worm, not polymorphism.","Encrypting files for ransom describes ransomware, a different category.","File-type specificity doesn't define polymorphic behavior.","Polymorphic viruses mutate their code each time to evade detection."]},
  {id:260,domain:T,question:"What is a Trojan dropper?",options:["File-encrypting ransomware demanding payment","A Trojan that deletes files","A Trojan that exfiltrates files to a C2","Malware that installs other malware"],answer:3,explanation:"A dropper's purpose is to deliver and install additional malicious payloads (ransomware, RATs, backdoors) on the victim system.",optionExplanations:["Ransomware encrypts and demands payment; a dropper installs other malware.","File deletion is a wiper's job, not a dropper's.","Data-stealing Trojans are stealers; droppers install other malware.","A dropper's sole purpose is delivering and installing more malware."]},
  {id:261,domain:A,question:"Which of the following is a security advantage of using private cloud over public cloud?",options:["Unlimited scalability without concerns","No need for encryption","Greater control and data isolation","Private cloud is always cheaper"],answer:2,explanation:"Private cloud gives organizations full control over their hardware, network, and data placement — important for sensitive data.",optionExplanations:["Public cloud offers greater scalability than private cloud.","Encryption is required in both private and public cloud.","Private cloud gives dedicated infrastructure and better isolation.","Private cloud usually costs more due to dedicated infrastructure."]},
  {id:262,domain:A,question:"What is the purpose of a demilitarized zone (DMZ) in a network?",options:["Eliminating the need for firewalls","Providing guest wireless access","Storing the organization's most sensitive internal data","Hosting public services between firewalls"],answer:3,explanation:"The DMZ isolates publicly accessible servers (web, email) from the internal network using a double-firewall architecture.",optionExplanations:["DMZs require firewalls; they don't eliminate the need for them.","Wireless access points are separate infrastructure from a DMZ.","The most sensitive data belongs in protected internal zones, not a DMZ.","A DMZ hosts public servers between external and internal firewalls."]},
  {id:263,domain:A,question:"What is the purpose of a proxy auto-config (PAC) file?",options:["Letting browsers pick a proxy per URL","Distributing VPN gateway settings to devices","Pushing DNS settings via DHCP","Pushing firewall ACL updates to edge devices"],answer:0,explanation:"A PAC file is a JavaScript function browsers call to decide whether to use a proxy and which one for each URL.",optionExplanations:["A PAC file lets browsers decide proxy use based on the URL.","VPN provisioning configures remote access, not browser proxy logic.","DHCP distributes DNS settings, unrelated to PAC files.","Dynamic firewall updates are threat intel integration, not PAC files."]},
  {id:264,domain:A,question:"Which cloud deployment model combines private and public cloud environments?",options:["Multi-cloud","Community cloud","Hybrid cloud","Public cloud"],answer:2,explanation:"Hybrid cloud links private and public cloud environments, enabling workloads to move between them based on needs.",optionExplanations:["Multi-cloud uses multiple public providers without a private link.","Community cloud is shared among similar organizations.","Hybrid cloud links private and public environments together.","Public cloud has no private component at all."]},
  {id:265,domain:A,question:"What is the risk of using default credentials on network devices?",options:["Attackers know defaults publicly","Defaults can never be changed","Defaults are more secure than custom credentials","Defaults use stronger vendor encryption"],answer:0,explanation:"Default credentials (admin/admin, admin/password) are documented in vendor manuals and widely known to attackers.",optionExplanations:["Default credentials are documented and widely known to attackers.","Defaults can and should be changed during hardening.","Defaults are weaker, not more secure, since they're identical across devices.","Defaults have no relation to encryption strength."]},
  {id:266,domain:O,question:"What is the purpose of a forensic write blocker?",options:["Compressing forensic disk images faster","Encrypting completed disk images","Restricting analysts from copying files","Reading media without modifying it"],answer:3,explanation:"A write blocker ensures forensic examination does not inadvertently alter evidence by blocking any write commands to the media.",optionExplanations:["Compression speeds acquisition; write blocking prevents modification.","Encryption protects images later; write blocking protects the source.","Blocking copies would hinder investigation, not what a write blocker does.","A write blocker allows reads while preventing any writes to evidence."]},
  {id:267,domain:O,question:"What is the purpose of a master boot record (MBR) in forensics?",options:["A PXE network boot server","A hardware chip storing keys (TPM)","The disk's first sector with boot code","A database of hashed passwords"],answer:2,explanation:"The MBR is forensically significant because malware (bootkits) can hide there before the OS loads, evading most security tools.",optionExplanations:["PXE boot servers deploy OS images, unrelated to the MBR.","A TPM stores keys; the MBR holds boot code and partitions.","The MBR is the first sector, holding boot code and partition data.","Password databases are the SAM or /etc/shadow, not the MBR."]},
  {id:268,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A secure development methodology","A financial compliance regulation","A knowledge base of adversary TTPs","A standardized incident response template"],answer:2,explanation:"MITRE ATT&CK catalogs attacker TTPs organized by attack lifecycle stages, used for threat hunting, detection, and red team planning.",optionExplanations:["Secure SDLC integrates security into development, not attacker TTPs.","Financial regulations like PCI DSS differ from this knowledge base.","ATT&CK catalogs real-world adversary tactics and techniques.","Incident templates are runbooks, not a threat knowledge base."]},
  {id:269,domain:O,question:"What is the Cyber Kill Chain?",options:["A compliance audit checklist","A model of sequential attack stages","A network zone architecture model","A vendor risk management methodology"],answer:1,explanation:"The Cyber Kill Chain models attacks in 7 stages: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, C2, Actions on Objectives.",optionExplanations:["Compliance checklists validate controls, not attack progression.","The Kill Chain models sequential stages attackers follow.","Zone architecture is a segmentation model, not attack staging.","Vendor risk management addresses suppliers, not attack lifecycle."]},
  {id:270,domain:O,question:"What is the difference between MTTD and MTTR?",options:["MTTD detects; MTTR repairs or recovers","MTTD measures restoration; MTTR measures detection","Both measure the same thing","Both measure time between incidents"],answer:0,explanation:"MTTD measures how long it takes to detect a threat; MTTR measures how long to recover. Both are key SOC performance metrics.",optionExplanations:["MTTD measures detection speed; MTTR measures recovery speed.","This reverses the two definitions.","They are distinct: one measures detection, the other recovery.","Neither metric measures time between separate incidents."]},
  {id:271,domain:P,question:"What is the purpose of a gap analysis in security?",options:["Targeted training after a phishing test","Comparing posture to a standard","Scanning hosts for open ports","Running endpoint malware detection"],answer:1,explanation:"A gap analysis identifies the difference between the current state of security and a desired target state (framework, standard, or regulation).",optionExplanations:["Training addresses gaps found, not the gap analysis itself.","A gap analysis compares current controls to a target standard.","Port scanning finds exposed services, not maturity gaps.","Malware detection is threat detection, not a gap analysis."]},
  {id:272,domain:P,question:"Which framework is specifically designed for securing industrial control systems (ICS)?",options:["NIST CSF","ISO 27001","PCI DSS","NERC CIP"],answer:3,explanation:"NERC CIP (North American Electric Reliability Corporation Critical Infrastructure Protection) standards apply to bulk electric system security.",optionExplanations:["NIST CSF is general-purpose, applicable across all sectors.","ISO 27001 is a general ISMS standard, not ICS-specific.","PCI DSS applies to payment card data, not ICS.","NERC CIP protects the bulk power system and electric utilities."]},
  {id:273,domain:P,question:"What is a penetration testing scope document?",options:["A post-test findings report","A prioritized remediation roadmap","An agreement on test scope and rules","A tool setup and configuration guide"],answer:2,explanation:"The scope document (rules of engagement) defines what can be tested, which methods are permitted, and the testing timeline.",optionExplanations:["A findings report comes after testing, not before it.","A remediation roadmap follows the test, not defines its scope.","The scope document sets boundaries, targets, and rules of engagement.","A tool setup guide is operational, not a legal scope agreement."]},
  {id:274,domain:P,question:"What is the purpose of a vulnerability disclosure policy?",options:["Rules for receiving and responding to reports","Paying monetary bounties for every confirmed vulnerability report","Auto-deploying patches within 24 hours","Requiring NDAs before any disclosure"],answer:0,explanation:"A VDP sets expectations for responsible disclosure, encouraging researchers to report vulnerabilities safely without legal fear.",optionExplanations:["A VDP sets a clear process and protections for reporting researchers.","A bug bounty is one mechanism, not the whole disclosure policy.","Patch timelines belong to patch management, not disclosure policy.","NDAs are legal instruments, not a disclosure process itself."]},
  {id:275,domain:P,question:"What is a memorandum of understanding (MOU) in security context?",options:["A technical configuration document","A fully binding legal contract","An itemized vendor invoice","A non-binding shared understanding"],answer:3,explanation:"An MOU documents mutual understanding and expectations, often used before a formal contract or for partner security agreements.",optionExplanations:["Configuration documents specify settings, not organizational relationships.","A binding contract has legal remedies; an MOU is typically non-binding.","Invoices are billing records, unrelated to an MOU's purpose.","An MOU establishes mutual expectations without full legal enforceability."]},
  {id:276,domain:G,question:"What is the difference between synchronous and asynchronous encryption?",options:["A shared clock signal vs. start/stop bits","Interchangeable terms for block ciphers","Asynchronous always outperforms synchronous in throughput","Synchronous means stream ciphers; asynchronous is nonstandard"],answer:3,explanation:"In some contexts, synchronous stream ciphers maintain an independent keystream; 'asynchronous' is not standard terminology in cryptography.",optionExplanations:["This conflates data transmission framing with cryptographic terminology.","They aren't interchangeable; synchronous refers to stream ciphers specifically.","Asynchronous isn't a recognized cryptographic performance category.","Synchronous stream ciphers use an independent keystream; asynchronous isn't standard terminology."]},
  {id:277,domain:G,question:"What is the purpose of a TPM (Trusted Platform Module)?",options:["A chip storing keys and measuring integrity","Protecting traffic with TLS via a security appliance","RADIUS/TACACS+ user authentication","Biometric fingerprint or facial scanning"],answer:0,explanation:"A TPM securely stores encryption keys, performs cryptographic operations, and attests to the integrity of the boot process.",optionExplanations:["A TPM securely stores keys and attests to boot integrity.","TLS protects network traffic; a TPM is a hardware chip.","RADIUS/TACACS+ authenticate over the network, not locally in hardware.","Biometric readers verify identity, not measure platform integrity."]},
  {id:278,domain:G,question:"Which type of encryption is used in HTTPS for the initial key exchange?",options:["Asymmetric encryption","No encryption during handshake","Symmetric encryption","Hashing"],answer:0,explanation:"TLS uses asymmetric encryption (RSA or ECDHE) during the handshake to securely exchange the symmetric session key.",optionExplanations:["Asymmetric encryption (or key agreement) establishes the session key.","TLS always encrypts the handshake parameters.","Symmetric encryption is used after the handshake, for bulk data.","Hashing provides integrity, not key exchange."]},
  {id:279,domain:G,question:"What is a supplicant in 802.1X authentication?",options:["The certificate authority","The switch or AP forwarding traffic","The RADIUS authentication server","The client device requesting access"],answer:3,explanation:"In 802.1X, the supplicant is the client (user's device) requesting access; the authenticator is the switch/AP; the auth server is RADIUS.",optionExplanations:["The CA issues certificates; it isn't a role in the 802.1X exchange.","The switch or AP is the authenticator, not the supplicant.","RADIUS is the authentication server, not the supplicant.","The supplicant is the client requesting network access."]},
  {id:280,domain:G,question:"What is a session key?",options:["A permanent key stored in an HSM","A long-term private key tied to a certificate","A temporary symmetric key generated for one session","A CA's dedicated certificate-signing key"],answer:2,explanation:"Session keys are ephemeral symmetric keys negotiated for each session, providing both speed (symmetric) and forward secrecy (temporary).",optionExplanations:["Permanent HSM keys are long-term, unlike a session key.","A PKI private key is long-term; a session key is short-lived.","A session key is a temporary symmetric key for one session.","CA signing keys sign certificates; session keys encrypt session data."]},
  {id:281,domain:T,question:"What is an ARP spoofing attack?",options:["Sending fake ARP replies for a spoofed IP","Impersonating a legitimate DHCP server on the LAN","Forging DNS responses","Flooding a switch's MAC table"],answer:0,explanation:"ARP spoofing poisons ARP caches on the LAN so traffic destined for a legitimate IP is sent to the attacker's MAC address.",optionExplanations:["ARP spoofing sends fake replies linking an attacker's MAC to a victim IP.","DHCP spoofing is a separate, related LAN attack.","Forging DNS responses describes DNS spoofing, not ARP spoofing.","MAC table flooding is a distinct switch-targeting technique."]},
  {id:282,domain:T,question:"What is a MAC flooding attack?",options:["Replaying wireless MAC handshakes","Spoofing one trusted MAC address","Sending malware in crafted packets","Overwhelming a switch's MAC table"],answer:3,explanation:"MAC flooding exhausts the CAM table, causing the switch to flood all traffic to all ports like a hub, enabling eavesdropping.",optionExplanations:["Wireless handshake replay targets Wi-Fi, not a switch's CAM table.","Spoofing one MAC is targeted impersonation, not table flooding.","Delivering malware via packets is a different delivery method.","MAC flooding overwhelms the CAM table, forcing broadcast mode."]},
  {id:283,domain:T,question:"What is DHCP spoofing?",options:["Blocking all DHCP traffic","Flooding the DHCP server with requests","Scanning for active DHCP servers","Acting as a rogue DHCP server"],answer:3,explanation:"A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker.",optionExplanations:["Blocking DHCP traffic is a defensive measure, not an attack.","Flooding the server describes DHCP starvation, a different attack.","Scanning for servers is passive recon, not spoofing itself.","A rogue DHCP server hands out false settings like a malicious gateway."]},
  {id:284,domain:T,question:"What is an SSL stripping attack?",options:["Swapping in a self-signed certificate","Deleting SSL certificate files","Extracting an org's private keys from a server","Downgrading HTTPS to HTTP mid-redirect"],answer:3,explanation:"SSL stripping intercepts the HTTP-to-HTTPS redirect and maintains an unencrypted connection with the victim while HTTPS is used with the server.",optionExplanations:["A fraudulent self-signed cert typically triggers browser warnings.","Deleting cert files would break HTTPS, not covertly intercept it.","Key extraction targets stored data; stripping works in real time.","SSL stripping intercepts the redirect, keeping the victim on HTTP."]},
  {id:285,domain:T,question:"Which of the following BEST describes a cross-site scripting (XSS) attack?",options:["Injecting scripts into others' browsers","Inserting SQL commands into form fields","Exploiting a server buffer overflow","Intercepting traffic between two servers"],answer:0,explanation:"XSS injects client-side scripts (JavaScript) into pages served to other users, executing in their browser's security context.",optionExplanations:["XSS injects scripts that execute in victims' browsers.","SQL injection targets the database, not the browser.","Buffer overflows corrupt server memory, unlike client-side XSS.","Server-to-server interception is a MITM, not client-side XSS."]},
  {id:286,domain:A,question:"What is a security zone in network architecture?",options:["A physically guarded area","A VLAN for security tools","A single subnet reserved only for DMZ servers","A segment with a defined trust level"],answer:3,explanation:"Security zones partition the network by trust level (trusted, untrusted, DMZ) and apply appropriate controls at zone boundaries.",optionExplanations:["Physical guarding is facility security, not network segmentation.","A tooling VLAN is a config detail, not the broader zone concept.","The DMZ is just one example zone among several trust levels.","Security zones partition networks by trust level with matching controls."]},
  {id:287,domain:A,question:"What is the purpose of subnetting in network security?",options:["Assigning MAC addresses to devices","Boosting throughput via hardware upgrades","Providing wireless access via APs","Splitting a network into segments"],answer:3,explanation:"Subnetting creates smaller network segments that limit broadcast domains and can restrict traffic flow between segments.",optionExplanations:["MAC addresses are burned in at the factory, unrelated to subnetting.","Throughput comes from hardware, not from subnetting itself.","Wireless access is delivered by APs, not IP addressing schemes.","Subnetting divides address space into smaller, isolated segments."]},
  {id:288,domain:A,question:"What is the role of an HSM in a PKI?",options:["Issuing certificates and validating identity","Publishing certificate revocation status","Protecting the CA's private key","Hosting a certificate request portal"],answer:2,explanation:"An HSM stores the CA's private key in tamper-resistant hardware, ensuring it cannot be extracted even if the CA server is compromised.",optionExplanations:["Issuing certificates is the CA software's job, not the HSM's.","Revocation status is published via CRLs/OCSP, not the HSM.","An HSM protects the CA's private key from extraction.","A request portal is a user-facing app, not the HSM's role."]},
  {id:289,domain:A,question:"What is meant by 'resilience' in security architecture?",options:["Deploying redundant tools from many vendors","Operating and recovering quickly","Blocking every possible attack","Running the fastest possible hardware"],answer:1,explanation:"Security resilience means systems can withstand or recover from disruptions without unacceptable loss of functionality.",optionExplanations:["Redundant tools help resilience but aren't the whole concept.","Resilience is absorbing disruption and recovering with minimal impact.","No architecture can prevent every attack; resilience is about recovery.","Raw processing speed is unrelated to surviving disruptions."]},
  {id:290,domain:A,question:"What is the purpose of a web application firewall (WAF)?",options:["Managing TLS certificates for a web server","Filtering packets by IP and port","Blocking web attacks like SQLi and XSS","Monitoring server CPU and memory"],answer:2,explanation:"A WAF analyzes HTTP/S requests and responses against security policies to block web application attacks.",optionExplanations:["TLS management is a server config task, not a WAF's core role.","IP/port filtering is done by traditional network firewalls.","A WAF inspects HTTP traffic to block attacks like SQLi and XSS.","Performance monitoring is an APM function, not a WAF's job."]},
  {id:291,domain:O,question:"What is the concept of 'dwell time' in security?",options:["An audit's scheduled duration","Time spent triaging one alert","How long an attacker goes undetected","Time to restore affected systems"],answer:2,explanation:"Dwell time (breakout time) is how long attackers lurk undetected; reducing it is a key goal of threat hunting and detection.",optionExplanations:["Audit duration is a scheduling detail, not a detection metric.","Analyst triage time relates to MTTR, not dwell time.","Dwell time measures how long an attacker persists undetected.","Restoration time is measured by MTTR, not dwell time."]},
  {id:292,domain:O,question:"What is the purpose of threat modeling?",options:["Deploying firewalls from a risk assessment","Training developers on secure coding","Prioritizing threats during design","Scanning production systems for vulnerabilities"],answer:2,explanation:"Threat modeling (STRIDE, PASTA, LINDDUN) systematically identifies threats early in design to guide security controls.",optionExplanations:["Firewall deployment may follow threat modeling, not define it.","Secure coding training is developer education, not threat modeling.","Threat modeling identifies design-time threats to guide security controls.","Vulnerability scanning tests built systems, not designs on paper."]},
  {id:293,domain:O,question:"What is the purpose of a security kernel?",options:["The crypto processor inside an HSM","A trusted OS core enforcing policy","A server running security monitoring tools","An undiscovered kernel vulnerability"],answer:1,explanation:"A security kernel is the smallest, most trusted portion of an OS — typically the TCB — that enforces all access control decisions.",optionExplanations:["HSM crypto processors are hardware appliances, not the OS concept.","A security kernel is the OS's trusted core enforcing all policy.","A security server runs tools; a security kernel is a design concept.","A kernel vulnerability is a specific flaw, not this architectural concept."]},
  {id:294,domain:O,question:"What is the difference between active and passive vulnerability scanning?",options:["Active scanning always finds more","Passive scanning is invasive while active never touches targets","Active probes directly; passive just observes","Active is manual; passive is automated"],answer:2,explanation:"Active scanning sends probes to systems; passive scanning observes traffic to infer vulnerabilities without touching target systems.",optionExplanations:["Which finds more depends on scope, not an inherent property.","This is reversed: active scanning is the more invasive method.","Active scanning probes systems directly; passive observes traffic only.","Both methods can be run manually or on an automated schedule."]},
  {id:295,domain:O,question:"What is a vulnerability scoring system (CVSS)?",options:["An active vulnerability scanning tool","A database of vendor patch releases","A catalog of CVE identifiers","A framework rating vulnerability severity"],answer:3,explanation:"CVSS (Common Vulnerability Scoring System) provides 0-10 severity scores based on exploitability, scope, and impact metrics.",optionExplanations:["Scanners like Nessus find flaws and report CVSS scores; they aren't CVSS itself.","A patch database tracks fixes; CVSS scores how severe flaws are.","CVE catalogs vulnerabilities by ID; CVSS scores their severity.","CVSS scores severity based on attack vector, complexity, and impact."]},
  {id:296,domain:P,question:"What is a system security plan (SSP)?",options:["A document outlining test cases for software quality","Documenting a system's security controls","A backup restoration procedure","A SOC daily monitoring schedule"],answer:1,explanation:"An SSP (required by NIST and FISMA) documents a system's security environment, control implementations, and responsibilities.",optionExplanations:["A test plan covers QA, not a system's security controls.","An SSP documents a system's security controls and requirements.","A recovery procedure restores data, distinct from an SSP.","A monitoring schedule is an operational SOC task list."]},
  {id:297,domain:P,question:"What is the purpose of an audit trail in security?",options:["Blocking unauthorized system access","Auto-triggering remediation on detection","A chronological record for accountability","Encrypting activity logs at rest"],answer:2,explanation:"An audit trail is an immutable log of events providing accountability, supporting investigations and demonstrating compliance.",optionExplanations:["Blocking access is a control function, not a record of events.","Automated response describes SOAR, not the audit trail itself.","An audit trail records who did what and when for accountability.","Log encryption protects storage; the trail itself is the record."]},
  {id:298,domain:P,question:"What is the concept of 'privacy by design'?",options:["An annual scheduled compliance review","Adding privacy controls after deployment","Encrypting every piece of personal data","Building privacy in from the start"],answer:3,explanation:"Privacy by design (Ann Cavoukian) integrates privacy as a core requirement from the start, not bolted on later.",optionExplanations:["An annual audit is periodic review, not built-in design.","Retrofitting privacy after deployment is what this concept avoids.","Encryption is one control; privacy by design is a broader philosophy.","Privacy by design embeds protections from the earliest design stage."]},
  {id:299,domain:P,question:"What does the term 'data sovereignty' mean?",options:["Unrestricted access to any online data","Data follows the laws of its host country","A legal doctrine that organizations automatically own all collected data","A universal encryption requirement everywhere"],answer:1,explanation:"Data sovereignty means data stored in a country is subject to that country's laws, affecting where organizations can store data.",optionExplanations:["Unrestricted access rights are unrelated to data sovereignty.","Data sovereignty means stored data falls under that country's laws.","Data ownership depends on contracts and law, not automatic sovereignty.","Encryption requirements vary by regulation, not a universal sovereignty rule."]},
  {id:300,domain:P,question:"What is a security charter?",options:["A network traffic and config rulebook","A signed legal document authorizing one pen test engagement","A firewall permission configuration list","Defining the security program's authority and scope"],answer:3,explanation:"A security charter grants the CISO and security program formal authority, defines scope, and establishes organizational accountability.",optionExplanations:["A network policy sets technical rules, not overall program authority.","Pen test authorization scopes one engagement, not the whole program.","Firewall rule lists are technical configs, not program charters.","A charter grants the security program its authority, scope, and goals."]},
  {id:301,domain:G,question:"What is the purpose of a time-based one-time password (TOTP)?",options:["Password manager cloud sync","A 30-second time-based one-time authentication code","Single sign-on (SSO)","Replacing all authentication factors"],answer:1,explanation:"TOTP (RFC 6238) generates a new 6-digit code every 30 seconds using HMAC-SHA1 and the current timestamp.",optionExplanations:["This describes a password manager, not TOTP.","TOTP generates a short-lived code using a shared secret and the current time.","This describes single sign-on (SSO), a separate concept.","TOTP is a second factor, not a full replacement for other authentication."]},
  {id:302,domain:G,question:"Which of the following BEST describes a hardware OTP token?",options:["Smart card with signing certificate","Offline OTP generator","USB drive storing passwords","Fingerprint scanning device"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey OTP) generate time or counter-based OTPs without network or battery in some models.",optionExplanations:["This describes a smart card used for digital signing, not a token.","A hardware OTP token creates codes locally without needing network access.","This describes passive storage, not active code generation.","This describes a biometric reader, an inherence factor, not a token."]},
  {id:303,domain:T,question:"What is a golden ticket attack in Active Directory?",options:["Physical data center break-in","LDAP injection attack","Forged TGT via KRBTGT hash","Fraudulent Microsoft support phishing"],answer:2,explanation:"By compromising the KRBTGT hash, attackers create forged TGTs valid for any account and resource, granting domain-wide persistence.",optionExplanations:["This is a physical security breach, unrelated to Kerberos.","This targets directory queries, not Kerberos tickets.","A golden ticket forges a TGT using the KRBTGT hash for domain-wide access.","This is a phishing technique, unrelated to ticket forgery."]},
  {id:304,domain:T,question:"What is a silver ticket attack?",options:["Extracting NTLM hashes from memory","Forged Kerberos service ticket","Weaker, shorter golden ticket","Kerberos replay attack"],answer:1,explanation:"Silver tickets forge Kerberos service tickets using a service account's hash, granting access to a specific service without KDC involvement.",optionExplanations:["This is credential theft from memory, not ticket forgery.","A silver ticket forges a service ticket using a service account hash, bypassing the KDC.","A silver ticket targets one service, not a scaled-down domain-wide ticket.","A replay attack reuses captured traffic; a silver ticket is freshly forged."]},
  {id:305,domain:T,question:"What is lateral movement in a cyberattack?",options:["Exfiltrating data to an external server","Escalating privileges on one host","Spreading across the network","Increasing DoS traffic volume"],answer:2,explanation:"Lateral movement uses techniques like pass-the-hash, RDP, and SSH to move from the beachhead to other targets in the network.",optionExplanations:["Exfiltration is usually the final goal, not the movement itself.","This is privilege escalation on a single host, not spreading further.","Lateral movement expands an attacker's foothold to additional systems.","This relates to DoS bandwidth, not spreading across systems."]},
  {id:306,domain:A,question:"What is micro-segmentation and how does it differ from traditional segmentation?",options:["Smaller VLAN subnets only","Same as traditional segmentation","Per-workload policy enforcement","Requires dedicated hardware appliances"],answer:2,explanation:"Micro-segmentation enforces policies per workload/VM using software-defined controls, much more granular than VLAN-based zone segmentation.",optionExplanations:["VLAN size isn't the real distinction; granularity of policy is.","The two differ significantly in granularity, so they aren't identical.","Micro-segmentation enforces policy at the individual workload level.","Micro-segmentation is typically software-defined, not hardware-dependent."]},
  {id:307,domain:A,question:"What security concern is associated with shadow IT?",options:["Unapproved monitoring software","Unauthorized staff overtime","Using unapproved cloud apps","Unpatched, unsupported legacy systems"],answer:2,explanation:"Shadow IT bypasses corporate security controls, potentially exposing sensitive data and creating compliance violations.",optionExplanations:["This is one narrow tool-approval issue, not the broader shadow IT problem.","This is an HR policy matter, unrelated to unsanctioned technology.","Shadow IT is unauthorized technology used outside IT's visibility and control.","This is a patch management issue, not unsanctioned technology adoption."]},
  {id:308,domain:A,question:"What is the purpose of network flow monitoring (NetFlow)?",options:["Traffic metadata analysis","Blocking malicious traffic in real time","Storing full packet payloads","Encrypting traffic between devices"],answer:0,explanation:"NetFlow/IPFIX captures flow records (metadata only) enabling traffic pattern analysis and anomaly detection at scale.",optionExplanations:["NetFlow records traffic metadata to enable pattern analysis and anomaly detection.","Blocking traffic is done by firewalls/IPS, not NetFlow, a passive tool.","Full packet capture is done by tools like Wireshark, not NetFlow.","Encryption is provided by TLS/IPsec, not NetFlow."]},
  {id:309,domain:O,question:"What is the purpose of endpoint hardening?",options:["Installing more applications","Adding users to local admin group","Upgrading hardware for speed","Removing unneeded services"],answer:3,explanation:"Endpoint hardening reduces attack surface by removing default accounts, disabling unneeded services, and applying security baselines.",optionExplanations:["More installed software expands the attack surface rather than reducing it.","Adding admin rights violates least privilege, the opposite of hardening.","Hardening targets security, not raw performance.","Hardening removes unnecessary services and applies secure configuration baselines."]},
  {id:310,domain:O,question:"What is a known-good baseline in security?",options:["Network topology diagram","Maximum achievable lockdown configuration","Antivirus signature database","Snapshot of normal system state"],answer:3,explanation:"A known-good baseline enables integrity monitoring — any deviation indicates unauthorized change or compromise.",optionExplanations:["This documents device connections, not a system's configuration state.","This is a hardening target, not the baseline itself, which documents normal state.","This is a malware detection database, unrelated to system baselines.","A baseline documents expected configuration to detect unauthorized changes."]},
  {id:311,domain:P,question:"Which regulation requires organizations to report data breaches to affected individuals within 72 hours?",options:["PCI DSS","SOX","GDPR","HIPAA"],answer:2,explanation:"GDPR Article 33 requires notifying the supervisory authority within 72 hours of becoming aware of a data breach.",optionExplanations:["PCI DSS covers card data security, not a 72-hour breach rule.","SOX governs financial reporting, not breach notification timelines.","GDPR requires authority notification within 72 hours of a breach.","HIPAA requires notification within 60 days, not 72 hours."]},
  {id:312,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["Encryption algorithm specification","Software license agreement","Internal, non-binding retention policy document","Contract for processor's data handling"],answer:3,explanation:"DPAs (required under GDPR) define the processor's obligations for processing personal data on behalf of the controller.",optionExplanations:["This is a technical standard, not a legal contract.","This is unrelated software licensing, not personal data handling.","A DPA is a binding contract, unlike an internal policy.","A DPA is a binding contract defining processor obligations under GDPR."]},
  {id:313,domain:P,question:"What is the concept of 'data minimization' in privacy?",options:["Compressing files to cut costs","Purging data right after processing","Collecting only needed data","Encrypting all personal data"],answer:2,explanation:"Data minimization (a GDPR principle) means collecting only what is strictly necessary, reducing privacy risk.",optionExplanations:["This is storage optimization, unrelated to limiting data collected.","This concerns retention/deletion timing, not limiting initial collection.","Minimization means collecting only data necessary for the stated purpose.","Encryption protects collected data; minimization limits what's collected."]},
  {id:314,domain:O,question:"What is a security operations maturity model?",options:["Framework for assessing program maturity","Benchmarking tool speed and detection accuracy","Roster of team certifications","Count of deployed security tools"],answer:0,explanation:"SOC maturity models (like the SOC-CMM) assess capabilities from ad hoc (Level 1) to optimized, metrics-driven programs (Level 5).",optionExplanations:["Maturity models assess people, process, and technology across levels.","This compares vendor tools, not overall program capability.","Certifications are one input, not the full maturity assessment.","Tool count says little about actual program effectiveness."]},
  {id:315,domain:T,question:"What is a living-off-the-land (LotL) attack?",options:["Attacking agricultural ICS equipment","Compromising a trusted vendor's update channel","Abusing built-in tools like PowerShell","Hiding code in sensor telemetry"],answer:2,explanation:"LotL attacks use built-in OS tools to blend in with normal activity, evading detection by not dropping external malware.",optionExplanations:["This describes an OT/ICS attack, unrelated to LotL technique.","This describes a supply chain attack, a distinct technique.","LotL attacks use pre-installed tools like PowerShell or WMI to evade detection.","This isn't a recognized technique; LotL means abusing existing system tools."]},
  {id:316,domain:T,question:"What is a pass-the-ticket attack?",options:["Brute-forcing Kerberos passwords","Hijacking a browser session cookie","Reusing a stolen Kerberos ticket","Harvesting Kerberos service account passwords"],answer:2,explanation:"Pass-the-ticket extracts Kerberos tickets from memory (using Mimikatz) and reuses them to authenticate to services.",optionExplanations:["Pass-the-ticket reuses an already-issued ticket; it doesn't guess passwords.","This is session hijacking via cookies, a separate technique.","Pass-the-ticket uses a stolen ticket to authenticate without a password.","This is credential harvesting, not reuse of an existing ticket."]},
  {id:317,domain:A,question:"What is a network tap?",options:["Firewall rule mirroring traffic","PCAP file analysis software","Temporary wireless survey access point","Passive hardware traffic tap"],answer:3,explanation:"A network tap passively copies traffic off a link (optical or electrical) to a monitoring device without affecting the original traffic.",optionExplanations:["This describes software port mirroring, not a hardware tap.","This describes analysis tools like Wireshark, not the capture device.","This describes a wireless survey tool, unrelated to wired taps.","A network tap is hardware that copies link traffic without added latency."]},
  {id:318,domain:A,question:"What is SPAN (Switched Port Analyzer)?",options:["Device authentication protocol","Wireless signal survey tool","Deep packet inspection firewall mode","A switch feature mirroring traffic to a monitor port"],answer:3,explanation:"SPAN (port mirroring) configures a switch to copy frames from selected ports to a monitoring port for analysis by IDS/sniffers.",optionExplanations:["SPAN mirrors traffic; it isn't an authentication protocol.","This is an RF survey tool, unrelated to switch port mirroring.","DPI actively inspects traffic; SPAN passively copies it for analysis.","SPAN copies traffic from selected ports to a monitoring port."]},
  {id:319,domain:O,question:"What is the purpose of a post-incident review (lessons learned)?",options:["Preserving legal evidence documentation","Formally assigning blame to individuals","Closing the incident ticket","Reviewing what happened to improve future response"],answer:3,explanation:"Post-incident reviews identify root causes, process improvements, and control gaps to strengthen defenses against future incidents.",optionExplanations:["Evidence preservation is part of chain of custody, not the review's focus.","Blame assignment discourages honesty; reviews focus on process improvement.","Closing a ticket is administrative, not a substantive improvement step.","Lessons-learned reviews analyze root cause and improve future response."]},
  {id:320,domain:O,question:"What is the role of the incident response team (IRT)?",options:["Delivering phishing awareness training","Handling incident response","Conducting annual penetration tests","Managing routine helpdesk operations"],answer:1,explanation:"The IRT (or CSIRT/CERT) detects, analyzes, contains, eradicates, and recovers from security incidents.",optionExplanations:["Awareness training is delivered by HR/security broadly, not the IRT specifically.","The IRT detects, contains, and recovers from security incidents.","Pen tests are scheduled assessments, not live incident handling.","Routine IT operations are handled by IT ops, not the IRT."]},
  {id:321,domain:G,question:"What is the purpose of a pre-shared key (PSK) in Wi-Fi security?",options:["Certificate-based device authentication","Dynamically rotated per-session keys","Shared Wi-Fi password","Encrypting only management frames"],answer:2,explanation:"PSK (used in WPA2/WPA3 Personal) is a shared passphrase all devices use; enterprise networks use 802.1X instead.",optionExplanations:["This describes 802.1X enterprise authentication, not PSK.","Per-session unique keys are a hallmark of 802.1X, not shared PSK.","A PSK is a shared passphrase used to derive the encryption key.","Frame protection is a separate feature (802.11w), not PSK's role."]},
  {id:322,domain:G,question:"What is the purpose of a Kerberos KDC?",options:["Processing LDAP directory queries","Translating private IPs via NAT","Issuing signed TLS certificates","Issuing Kerberos tickets"],answer:3,explanation:"The Key Distribution Center (KDC) contains the Authentication Server (AS) and Ticket Granting Server (TGS) for Kerberos.",optionExplanations:["Directory queries are handled by AD; the KDC issues tickets instead.","NAT translates addresses; the KDC manages authentication tickets.","TLS certificates come from a CA; the KDC issues Kerberos tickets.","The KDC issues TGTs and service tickets for password-free authentication."]},
  {id:323,domain:T,question:"What is the purpose of network reconnaissance tools like Nmap?",options:["Encrypting network traffic","Blocking malicious traffic automatically","Establishing an encrypted VPN tunnel","Scanning hosts and open ports"],answer:3,explanation:"Nmap is a network scanner used to discover live hosts, open ports, running services, and OS fingerprints.",optionExplanations:["Nmap doesn't encrypt traffic; it probes for open services.","Blocking traffic is done by firewalls/IPS, not a scanner like Nmap.","VPNs create encrypted tunnels; Nmap instead discovers network hosts and ports.","Nmap discovers live hosts, open ports, and running services."]},
  {id:324,domain:T,question:"What is a credential harvesting attack?",options:["Cracking stolen password hashes offline","Automated login guessing at scale","Generating default IoT credential lists","Deceiving users via fake pages"],answer:3,explanation:"Credential harvesting tricks users into submitting credentials to attacker-controlled pages through phishing, fake sites, or malware.",optionExplanations:["This is offline hash cracking, not tricking a live user.","This is brute forcing, not deception-based credential theft.","Default credential lists target weak configs, not deceived users.","Harvesting tricks users into submitting credentials via fake pages or forms."]},
  {id:325,domain:A,question:"What is the purpose of rate limiting in web security?",options:["Encrypting API responses","Speeding up backend caching","Logging every incoming request","Limiting how many requests a client can send"],answer:3,explanation:"Rate limiting prevents brute force, credential stuffing, and API abuse by limiting how many requests a client can make per unit time.",optionExplanations:["TLS handles response encryption; rate limiting controls request frequency.","Rate limiting restricts requests rather than speeding up responses.","Logging records requests; rate limiting actively restricts their frequency.","Rate limiting caps requests per client to prevent abuse and brute force."]},
  {id:326,domain:P,question:"Which of the following is a primary security control objective of HIPAA Security Rule?",options:["Mandatory MFA for every user","CIA protection of ePHI","Encrypting every single email","Banning cloud storage of PHI"],answer:1,explanation:"The HIPAA Security Rule requires covered entities to protect the CIA of all electronic protected health information.",optionExplanations:["HIPAA doesn't explicitly mandate MFA by name.","The Security Rule requires protecting confidentiality, integrity, and availability of ePHI.","HIPAA recommends but doesn't mandate encrypting every email.","HIPAA allows cloud storage if covered by a signed BAA."]},
  {id:327,domain:O,question:"What is the function of a security information broker?",options:["Reselling stolen data on dark markets","Supplying only threat intel feeds","Tracking vendor security questionnaires","Aggregating security data"],answer:3,explanation:"A security data broker aggregates logs and events from multiple disparate systems into a common format for analysis.",optionExplanations:["This describes a criminal data broker, not a legitimate security tool.","Threat intel is just one data type; a broker handles data broadly.","Vendor assessments are a GRC/procurement task, not a data broker function.","A security information broker aggregates and normalizes data from many sources."]},
  {id:328,domain:O,question:"What is the purpose of a continuous monitoring program?",options:["Annual security training refresher","One formal comprehensive assessment done annually","Quarterly patch rollout","Persistent real-time security visibility"],answer:3,explanation:"Continuous monitoring provides real-time or near-real-time visibility into security posture, replacing periodic point-in-time assessments.",optionExplanations:["Training is one program component; monitoring is an ongoing technical capability.","Annual assessments are periodic snapshots; monitoring is continuous, not yearly.","Patch cadence is fixed; monitoring detects issues as they emerge.","Continuous monitoring maintains ongoing awareness of vulnerabilities and threats."]},
  {id:329,domain:G,question:"What is the PBKDF2 algorithm used for?",options:["Encrypting bulk file data fast","Deriving keys from passwords","Negotiating a TLS session key","Generating an asymmetric key pair"],answer:1,explanation:"PBKDF2 (Password-Based Key Derivation Function 2) strengthens passwords by applying HMAC many times with a salt.",optionExplanations:["Bulk encryption uses fast ciphers like AES; PBKDF2 derives keys instead.","PBKDF2 applies salt and iterations to derive a strong key from a password.","TLS key exchange uses protocols like Diffie-Hellman, not PBKDF2.","Asymmetric key pairs come from RSA/ECDSA, not PBKDF2."]},
  {id:330,domain:T,question:"What is the purpose of obfuscation in malware?",options:["Speeding up payload execution","Hiding malicious code to evade detection tools","Replicating faster across systems","Encrypting files for ransom"],answer:1,explanation:"Malware obfuscation (encoding, packing, polymorphism) disguises code to evade signature-based detection and complicate reverse engineering.",optionExplanations:["Obfuscation adds overhead; it doesn't improve execution speed.","Obfuscation disguises code to evade signature-based detection and analysis.","Faster spreading is a propagation technique, not code disguising.","Encrypting victim files for ransom is what ransomware payloads do."]},
  {id:331,domain:A,question:"What is network address translation (NAT) and how does it help security?",options:["Blocking every inbound connection","Encrypting internal-to-external traffic","Verifying user identity credentials","Masking internal addressing"],answer:3,explanation:"NAT hides internal IP addressing from external attackers, reducing reconnaissance information about the internal network.",optionExplanations:["NAT can incidentally hinder unsolicited traffic, but blocking is a firewall's job.","NAT translates addresses; it doesn't encrypt traffic.","Authentication is handled by IAM, not NAT.","NAT maps internal IPs to a public one, hiding internal topology."]},
  {id:332,domain:A,question:"What is the purpose of 802.11w (Protected Management Frames)?",options:["Encrypting wireless data frame payloads","Legacy WPA3 compatibility layer","Boosting wireless throughput speed","Protecting management frames"],answer:3,explanation:"802.11w protects management frames so attackers cannot send fake deauthentication frames to disconnect clients.",optionExplanations:["Data payload encryption is handled by CCMP/GCMP, not 802.11w.","802.11w is a security amendment WPA3 requires, not just a compatibility layer.","802.11w adds overhead for security, not speed.","802.11w protects management frames from spoofing and deauthentication attacks."]},
  {id:333,domain:T,question:"What is a JPEG or PDF file used to deliver malware called?",options:["Kernel-level rootkit","Macro-enabled virus","Boot-sector bootkit","A malicious document (maldoc) delivering malware"],answer:3,explanation:"Malicious documents (maldocs) embed exploits or malicious macros in PDFs, Office files, or image metadata to deliver malware.",optionExplanations:["A rootkit hides at the OS level; this is a delivery mechanism instead.","Macro viruses are one subset; maldocs include PDF exploits too.","A bootkit infects the boot process; maldocs exploit document viewers.","Maldocs are weaponized files like PDFs or Office docs used to deliver malware."]},
  {id:334,domain:O,question:"What is the purpose of network segmentation in limiting ransomware spread?",options:["Blocking encryption on the infected host","Limiting spread to other segments","Flagging ransomware before execution","Speeding up backup recovery"],answer:1,explanation:"Segmentation limits ransomware's lateral movement, confining it to the segment where it first landed.",optionExplanations:["Segmentation can't stop encryption on an already-infected host.","Segmentation confines ransomware to the segment where it first landed.","Pre-execution detection is done by EDR, not segmentation.","Recovery speed depends on backups, not segmentation."]},
  {id:335,domain:P,question:"What is the concept of 'right to erasure' (right to be forgotten) under GDPR?",options:["Instant deletion of any record on request","Deletion right with legal exceptions","Applies only to data over 10 years old","Applies only to financial records"],answer:1,explanation:"GDPR Article 17 grants individuals the right to request data deletion when data is no longer necessary or consent is withdrawn.",optionExplanations:["Erasure isn't unconditional; organizations may refuse with legal grounds.","GDPR lets individuals request deletion, with exceptions like legal obligations.","Erasure isn't tied to any minimum data age.","Erasure applies broadly, not just to financial data."]},
  {id:336,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Backing up CA private keys","Revoking certificates via a CRL","A public audit log of all issued certificates","Replacing OCSP for revocation checks"],answer:2,explanation:"CT logs create an auditable, append-only record of all certificates issued by CAs, enabling domain owners to detect unauthorized certs.",optionExplanations:["Private keys are never placed in public logs like CT.","Revocation uses CRLs/OCSP; CT logs track issuance, not revocation.","CT logs give public visibility into all issued certificates.","OCSP still handles revocation; CT logs serve auditing, not replacement."]},
  {id:337,domain:G,question:"What is a certificate signing request (CSR)?",options:["Requesting certificate revocation","A formal request to a CA for a signed certificate","Extending a certificate's validity","The CA's signature on a certificate"],answer:1,explanation:"A CSR contains the entity's public key and identity (CN, SAN, organization) and is signed with the corresponding private key.",optionExplanations:["Revocation requests are separate from requesting a new certificate.","A CSR carries the applicant's public key and identity to the CA for signing.","Renewal is a distinct process, not the CSR itself.","The CA's signature comes after the CSR, not the CSR itself."]},
  {id:338,domain:T,question:"What is a pass-the-certificate attack?",options:["Forging a new root CA certificate","Logging in with a stolen plaintext password","Authenticating with a stolen digital certificate and key","Phishing via fake certificate warnings"],answer:2,explanation:"Pass-the-certificate reuses stolen certificates and private keys (from certificate stores) to authenticate to services that accept certificate authentication.",optionExplanations:["Forging a root CA cert requires compromising the CA itself, unlike reusing a stolen cert.","Stolen password login is basic credential theft, not certificate-based.","This attack reuses a stolen certificate and key instead of a password.","Fake warning phishing tricks users; this attack uses genuine stolen credentials."]},
  {id:339,domain:O,question:"What is the purpose of a deception technology solution?",options:["Replacing firewalls, IDS, and SIEM","Blocking every intrusion at the perimeter","Teaching offensive red team tactics","Creating decoy assets"],answer:3,explanation:"Deception technology (honeypots, honeyfiles, fake credentials) alerts defenders when attackers interact with decoy assets.",optionExplanations:["Deception supplements existing tools rather than replacing them.","Deception detects attackers already inside, not prevents entry.","Red team training teaches techniques directly; deception is a passive defense.","Deception technology lures attackers to fake assets to detect them."]},
  {id:340,domain:P,question:"What is the purpose of a security awareness training program metric?",options:["Assessing security staff certifications","Counting deployed security tools","Recording training attendance only","Measuring behavior change"],answer:3,explanation:"Meaningful metrics (phishing click rates, reporting rates, policy quiz scores) measure behavioral change, not just compliance.",optionExplanations:["Staff certifications are assessed separately from general awareness training.","Tool count doesn't reflect employee behavior.","Attendance alone doesn't show whether behavior actually changed.","Good metrics track behavior change, like phishing click-through rates."]},
  {id:341,domain:G,question:"What is the purpose of a security assertion markup language (SAML) assertion?",options:["Tracking and publishing certificate revocation status","Signing outgoing emails","Hashing a stored password","Confirms authentication to a service provider"],answer:3,explanation:"A SAML assertion is an XML statement from the IdP to the SP declaring the user's identity and attributes after authentication.",optionExplanations:["Revocation is tracked via CRL/OCSP, unrelated to SAML.","Email signing uses S/MIME or PGP, not SAML.","Password hashing is done by the identity store, not SAML.","A SAML assertion is the IdP's signed confirmation of authentication for SSO."]},
  {id:342,domain:G,question:"What is OpenID Connect (OIDC)?",options:["Encrypting API transport traffic","Identity layer on OAuth 2.0","Standard defining X.509 certificate structure","Protocol for distributing cryptographic keys"],answer:1,explanation:"OIDC adds an identity layer to OAuth 2.0, providing ID tokens (JWT) with user identity claims for authentication.",optionExplanations:["TLS handles transport encryption; OIDC handles authentication.","OIDC adds authentication and identity tokens on top of OAuth 2.0.","X.509 governs certificates; OIDC uses JWTs for identity instead.","Key management is handled by KMS, not OIDC."]},
  {id:343,domain:T,question:"What is a fileless attack that uses PowerShell for malicious purposes called?",options:["Macro virus in an Office document","PowerShell LotL attack","Kernel-level rootkit","Destructive wiper attack"],answer:1,explanation:"Attackers use legitimate PowerShell to download payloads, manipulate systems, and evade detection without dropping files.",optionExplanations:["Macro viruses live in documents; this attack runs via scripting, no macro needed.","Using PowerShell for malicious ends is a classic living-off-the-land technique.","Rootkits hide at the kernel level; this operates at the scripting level.","Wipers purely destroy data; this attack's goals vary by intent."]},
  {id:344,domain:T,question:"What is the primary security risk of IoT devices?",options:["Complex initial setup procedures","High purchase and licensing cost","Excessive bandwidth consumption","Weak default credentials and missing security updates"],answer:3,explanation:"IoT devices frequently run outdated firmware, use default credentials, and cannot be patched, creating persistent network vulnerabilities.",optionExplanations:["Setup difficulty is a usability issue, not the core security risk.","Cost is a procurement issue, not a security risk itself.","Bandwidth use is a performance concern, not the main security risk.","IoT devices often ship with default credentials and lack update mechanisms."]},
  {id:345,domain:A,question:"What is a VPC (Virtual Private Cloud)?",options:["Dedicated private data center at a cloud site","Isolated cloud network for one customer","Encrypted VPN tunnel for remote access","Managed VPN service hosted in the cloud"],answer:1,explanation:"A VPC provides network isolation within a public cloud, allowing customers to define their own IP ranges, subnets, and routing.",optionExplanations:["A VPC is shared cloud infrastructure, logically isolated, not dedicated physical hardware.","A VPC is a logically isolated network section within a public cloud.","A VPN creates an encrypted tunnel; a VPC is a network construct, not a tunnel.","A VPC can host VPN endpoints but isn't itself a VPN service."]},
  {id:346,domain:A,question:"What is the purpose of a cloud security posture management (CSPM) tool?",options:["Encrypting cloud storage data","Replacing native cloud security controls","Detecting cloud misconfigurations","Establishing VPN gateway connections"],answer:2,explanation:"CSPM tools automatically detect and remediate cloud misconfigurations (public S3 buckets, open security groups) that expose organizations.",optionExplanations:["Encryption is a control CSPM monitors, not one it performs.","CSPM adds visibility on top of native controls, not a replacement.","CSPM continuously detects misconfigurations and compliance violations in cloud environments.","VPN connectivity is a separate function from configuration monitoring."]},
  {id:347,domain:O,question:"What is the OODA loop and how does it apply to security?",options:["Categorizing incidents by severity tier","Protocol for reporting monitoring telemetry","The Observe-Orient-Decide-Act rapid decision cycle","Framework for reverse-engineering malware"],answer:2,explanation:"The OODA loop enables faster decision-making cycles than attackers — observing what's happening, orienting to context, deciding, and acting.",optionExplanations:["Severity tiers prioritize response; OODA is the decision-making model itself.","Telemetry reporting is a monitoring protocol, not a decision framework.","OODA helps security teams observe, orient, decide, and act faster than attackers.","Malware analysis uses sandboxing/reverse engineering, a separate discipline from OODA."]},
  {id:348,domain:O,question:"What does IoC (Indicator of Compromise) differ from an IoA (Indicator of Attack)?",options:["Past compromise evidence versus ongoing attack behavior","IoCs prevent; IoAs only detect after the fact","IoAs are always more accurate than IoCs","IoCs and IoAs are identical concepts"],answer:0,explanation:"IoCs (file hashes, IPs) are forensic artifacts after compromise; IoAs (lateral movement patterns) indicate an attack in progress.",optionExplanations:["IoCs are post-compromise artifacts; IoAs are real-time behavioral signals of an active attack.","The roles are reversed — IoCs mainly aid detection/forensics after the fact.","Neither is universally more accurate; both have distinct value.","IoCs and IoAs serve different purposes, so they aren't interchangeable."]},
  {id:349,domain:P,question:"What is the concept of 'privacy engineering'?",options:["GDPR compliance training for developers","Building surveillance systems for law enforcement","Integrating privacy into engineering","Annual review of privacy policies"],answer:2,explanation:"Privacy engineering applies technical methods to identify and mitigate privacy risks throughout system design and development.",optionExplanations:["Training raises awareness; privacy engineering builds protections into systems directly.","Building surveillance systems is essentially the opposite of privacy protection.","Privacy engineering embeds privacy requirements throughout the development lifecycle.","Policy review is periodic auditing, not ongoing technical design."]},
  {id:350,domain:G,question:"What is a hybrid encryption scheme?",options:["Combining two symmetric algorithms","Separate keys for auth and encryption","Encrypting data twice with different keys","Asymmetric-protected symmetric key"],answer:3,explanation:"Hybrid encryption (used in TLS, PGP) uses asymmetric to securely exchange a symmetric key, then symmetric for fast bulk data encryption.",optionExplanations:["This is double/cascade encryption, not the asymmetric-symmetric pairing that defines hybrid.","Separate auth/encryption keys is a key management practice, not hybrid encryption.","Double encryption with the same algorithm type isn't what makes it hybrid.","Hybrid encryption uses asymmetric encryption to protect a symmetric key for fast bulk encryption."]},
  {id:351,domain:T,question:"What is a watering hole attack?",options:["Compromising a frequented website","Spear phishing specific individuals","Flooding a server with traffic","Intercepting communications between two parties"],answer:0,explanation:"Watering hole attacks compromise websites that the target group frequently visits, allowing attackers to infect visitors without direct contact.",optionExplanations:["A watering hole attack compromises websites the target group often visits.","Spear phishing targets individuals directly via email, not via a compromised site.","Flooding a server describes a DoS attack, unrelated to site compromise.","Intercepting communications describes a man-in-the-middle attack, not a watering hole."]},
  {id:352,domain:G,question:"What is key escrow in cryptography?",options:["Splitting a key across multiple servers","Deriving a shared key collaboratively","Third party holds a key copy","Storing keys in a tamper-resistant HSM"],answer:2,explanation:"Key escrow allows authorized parties (law enforcement, recovery agents) to access encrypted data by retrieving the stored key copy.",optionExplanations:["Splitting a key into fragments describes threshold cryptography, not escrow.","Deriving a shared key describes Diffie-Hellman, not storing a copy for recovery.","Key escrow lets an authorized third party recover data using a stored key copy.","HSMs protect the original key; escrow specifically gives a copy to a third party."]},
  {id:353,domain:A,question:"What is a jump server (jump box) used for in network security?",options:["Benchmarking network throughput and latency","Running scheduled vulnerability scans","Routing packets between VLANs","Gateway into secure zones"],answer:3,explanation:"Jump servers provide a controlled access point to sensitive network zones, logging all activity and reducing direct exposure of internal systems.",optionExplanations:["Throughput testing uses tools like iPerf, unrelated to jump box function.","Vulnerability scanning is done by tools like Nessus, not a jump box.","VLAN routing is a Layer 3 switch/router function, not a jump box.","A jump server is a hardened checkpoint for accessing sensitive network segments."]},
  {id:354,domain:O,question:"What is the primary purpose of security information and event management (SIEM) correlation rules?",options:["Auto-deploying vendor patches","Correlating patterns across logs","Compressing archived logs to save costs","Encrypting stored log data"],answer:1,explanation:"SIEM correlation rules analyze events from multiple sources to detect attack patterns like brute force, lateral movement, or data exfiltration.",optionExplanations:["Patch management fixes vulnerabilities directly; correlation instead detects events.","Correlation rules link events across sources to reveal attack patterns.","Log compression saves storage; correlation extracts security meaning instead.","Log encryption protects confidentiality; correlation analyzes content for threats."]},
  {id:355,domain:T,question:"What distinguishes a zero-day exploit from a known vulnerability exploit?",options:["Known exploits are always more reliable","A zero-day exploits a still-unknown, unpatched vulnerability","Zero-days only affect operating systems","Zero-days pose less risk than known exploits"],answer:1,explanation:"Zero-day exploits target vulnerabilities the vendor doesn't know about, so no patch exists, making them extremely valuable and dangerous.",optionExplanations:["Zero-days actually have the advantage of no defenses being in place yet.","A zero-day targets a flaw unknown to the vendor, so no patch exists yet.","Zero-days can affect any software layer, not just operating systems.","Zero-days are typically more dangerous since no patch or signature exists yet."]},
  {id:356,domain:P,question:"What is the purpose of a data retention policy?",options:["Replicating data across locations for redundancy","Keeping all data permanently","Classifying data by sensitivity level","Setting retention periods before deletion"],answer:3,explanation:"Data retention policies balance legal/regulatory requirements (keeping records) with privacy obligations (deleting personal data when no longer needed).",optionExplanations:["Replication is a redundancy/continuity control, not a retention rule.","Keeping data forever creates cost and privacy liabilities; retention sets limits instead.","Classification assigns sensitivity levels; retention separately sets how long to keep data.","Retention policies define how long data types are kept and when deleted."]},
  {id:357,domain:A,question:"What is network segmentation and why is it a security control?",options:["Filtering email attachments at the gateway","Increasing available network bandwidth","Encrypting traffic end-to-end","Isolating network zones"],answer:3,explanation:"Network segmentation contains breaches by limiting how far attackers can move — a compromised guest network can't reach production systems.",optionExplanations:["Email filtering protects against attachments; segmentation controls network paths.","Bandwidth is a performance concern, unrelated to security segmentation.","Encryption protects data in transit; segmentation controls who can communicate.","Segmentation isolates zones to limit lateral movement and contain breaches."]},
  {id:358,domain:O,question:"What is the goal of a tabletop exercise in incident response?",options:["Measuring latency during simulated attacks","Testing technical response tools live","Validating backup restoration procedures","Discussion-based scenario walkthrough"],answer:3,explanation:"Tabletop exercises identify communication gaps, unclear responsibilities, and missing procedures without executing actual response actions.",optionExplanations:["Performance stress testing is technical, not the discussion-based tabletop format.","Testing actual tools happens in functional exercises, not a tabletop discussion.","Backup validation is a separate technical recovery test.","Tabletop exercises walk through a scenario to reveal gaps in plans and roles."]},
  {id:359,domain:G,question:"What is the difference between symmetric and asymmetric encryption in terms of key management?",options:["Identical key management for both","Asymmetric requires an HSM to function","Symmetric uses two keys; asymmetric uses one","One shared key vs. a public/private pair"],answer:3,explanation:"Symmetric key distribution is the challenge (how to share the secret securely); asymmetric solves this with freely shareable public keys.",optionExplanations:["Their key management approaches differ fundamentally, not identically.","HSMs can optionally protect asymmetric keys, but aren't required.","This reverses it — symmetric uses one key, asymmetric uses a pair.","Symmetric encryption shares one key; asymmetric uses a public/private key pair."]},
  {id:360,domain:T,question:"What is credential stuffing?",options:["Reusing breached logins elsewhere","Hardcoding default credentials in malware","Creating synthetic test credentials","Brute-forcing password hashes offline"],answer:0,explanation:"Credential stuffing exploits password reuse — attackers take breach dumps and try those credentials against banks, email, and other high-value sites.",optionExplanations:["Credential stuffing automates login attempts using breached credentials, exploiting reuse.","Hardcoded credentials in malware/firmware is a persistence technique, not this attack.","Synthetic test credentials are a legitimate QA practice, unrelated to this attack.","Brute forcing hashes is offline cracking, not live login attempts."]},
  {id:361,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["Virtual firewall filtering cloud zones","Software-defined DMZ architecture","One-to-one authorized connections","Cloud-hosted signature-based IDS"],answer:2,explanation:"SDP hides network resources until after authentication and authorization, making infrastructure invisible to unauthorized users (implements zero trust).",optionExplanations:["Virtual firewalls filter traffic between segments; SDP hides resources until authorized.","A software-defined DMZ is still a perimeter zone; SDP removes the perimeter entirely.","SDP authenticates first, then grants a hidden, direct connection to authorized resources.","Cloud IDS detects known threats; SDP instead controls access by hiding resources."]},
  {id:362,domain:O,question:"What is the purpose of a business impact analysis (BIA)?",options:["Reviewing IT uptime and latency metrics","Assessing employee productivity levels","Assessing critical function impact","Analyzing competitor business strategy"],answer:2,explanation:"The BIA identifies critical functions, recovery time objectives (RTO), recovery point objectives (RPO), and financial impact of downtime.",optionExplanations:["IT performance metrics are routine ops monitoring, not business impact analysis.","Employee productivity is an HR concern, separate from a BIA.","A BIA identifies critical processes and quantifies the impact of disruption.","Competitor analysis is a business intelligence activity, not a BIA."]},
  {id:363,domain:T,question:"What is a living off the land (LotL) attack technique?",options:["Abusing built-in system tools","Planting rogue hardware to intercept traffic","Attacking agricultural IoT sensors","Social engineering for physical access"],answer:0,explanation:"LotL attacks abuse trusted tools already present on systems, making detection difficult since the tools are legitimate and expected to run.",optionExplanations:["LotL attackers abuse trusted tools like PowerShell or WMI already on the system.","Planting hardware is a physical intrusion technique, not software-based LotL.","LotL applies broadly, not specifically to agricultural IoT.","Gaining physical access via social engineering is a distinct attack vector."]},
  {id:364,domain:G,question:"What is the role of a certificate revocation list (CRL)?",options:["Preinstalled list of trusted root CAs","Registry of every certificate ever issued","Internal list of certificates pending renewal","Certificates revoked before expiry"],answer:3,explanation:"CRLs allow relying parties to check if a certificate has been revoked due to key compromise, CA compromise, or policy violation.",optionExplanations:["Trusted root CAs are stored in a trust store, not a CRL.","A full issuance registry differs from a CRL, which lists only revoked certs.","Renewal-pending lists are internal CA admin data, not published revocation status.","A CRL publishes certificates revoked before their natural expiration."]},
  {id:365,domain:P,question:"What is a privacy impact assessment (PIA)?",options:["Reviewing network security controls","Evaluating data center physical security","Assessing data privacy risk","Auditing privacy training completion"],answer:2,explanation:"PIAs identify how personal data will be collected, used, stored, and shared, and assess risks to individuals' privacy rights.",optionExplanations:["Network reviews are technical infrastructure checks, not privacy-focused.","Physical security assessments cover facilities, not data privacy risk.","A PIA evaluates how personal data is collected, used, and shared, and its privacy risks.","Training audits check staff completion, not the privacy risk of a specific process."]},
  {id:366,domain:A,question:"What is microsegmentation in cloud and virtualized environments?",options:["Deploying apps to separate cloud regions","East-west traffic policy control","Splitting one server into multiple VMs","Prioritizing traffic by packet size"],answer:1,explanation:"Microsegmentation applies policies between individual VMs or containers, preventing lateral movement even within the same network segment.",optionExplanations:["Separate regions provide geographic redundancy, not workload-level policy.","Microsegmentation enforces policy between individual workloads, limiting lateral movement.","Creating VMs is virtualization itself; microsegmentation applies policy on top of it.","Prioritizing by packet size is a QoS concept, not security policy."]},
  {id:367,domain:O,question:"What is threat hunting?",options:["Proactively hunting for signs of hidden compromise","Deploying honeypots to lure attackers","Running scheduled vulnerability scans","Reactively investigating existing alerts"],answer:0,explanation:"Threat hunters assume compromise has occurred and use hypotheses, data analysis, and security expertise to find hidden attackers.",optionExplanations:["Threat hunting proactively searches for adversaries that evaded automated detection.","Honeypots are passive deception tools; hunting actively searches production systems.","Vulnerability scanning finds known weaknesses on schedule, not active adversaries.","Responding to alerts is reactive; hunting assumes detection already failed."]},
  {id:368,domain:T,question:"What is a command and control (C2) server in the context of malware?",options:["Vendor server distributing verified patches","Security appliance removing malware","Server managing SSO credentials","Attacker-controlled infrastructure directing compromised machines"],answer:3,explanation:"C2 infrastructure allows attackers to control botnets and malware remotely, issuing instructions and exfiltrating data from compromised hosts.",optionExplanations:["Legitimate update servers are trusted; C2 sometimes mimics that traffic to blend in.","Security tools remove malware; C2 servers instead direct it remotely.","Authentication servers manage legitimate logins, not compromised hosts.","C2 infrastructure sends commands to and receives data from compromised machines."]},
  {id:369,domain:G,question:"What is forward secrecy (perfect forward secrecy)?",options:["Session keys stay protected even after a later private key compromise","Pre-encrypting future communications in advance","Generating backup keys before expiration","Forwarding packets to redundant servers"],answer:0,explanation:"PFS uses ephemeral key exchange (ECDHE/DHE) so each session has a unique key — past traffic stays secure even if the private key is stolen later.",optionExplanations:["PFS uses ephemeral keys so a later private-key compromise can't expose past sessions.","Pre-encrypting future traffic isn't a real cryptographic concept.","Generating backup keys is routine key management, not forward secrecy.","Forwarding to redundant servers is a routing concept, unrelated to PFS."]},
  {id:370,domain:O,question:"What is the difference between RTO and RPO in disaster recovery?",options:["RTO caps downtime; RPO caps data loss","RTO and RPO measure the same thing","RPO measures restore speed; RTO measures backup frequency","RTO applies only to databases"],answer:0,explanation:"RTO (Recovery Time Objective) defines how quickly systems must be restored; RPO (Recovery Point Objective) defines how much data loss is acceptable.",optionExplanations:["RTO defines maximum downtime; RPO defines maximum tolerable data loss.","RTO and RPO measure distinct things: downtime tolerance vs. data loss tolerance.","This reverses the definitions — RPO drives backup frequency, RTO drives restore speed.","Both RTO and RPO apply to any critical system, not just databases."]},
  {id:371,domain:T,question:"What is a rootkit?",options:["Malware hiding deep within the OS to conceal itself","Bundled admin maintenance scripts","Legitimate remote support tool","Utility for managing root accounts"],answer:0,explanation:"Rootkits modify the OS kernel or bootloader to hide processes, files, and network connections, making detection and removal extremely difficult.",optionExplanations:["Rootkits subvert OS functions to hide processes, files, and connections from detection.","Admin scripts are legitimate, visible tools, unlike a concealed rootkit.","Legitimate remote access tools are authorized; rootkits hide unauthorized presence.","Root account management tools are legitimate, unlike a rootkit's hidden persistence."]},
  {id:372,domain:A,question:"What is a web application firewall (WAF) designed to protect against?",options:["Network-level DDoS floods","SQL injection and XSS attacks","Malware on employee endpoints","Physical access to the data center"],answer:1,explanation:"WAFs inspect HTTP/HTTPS traffic and block attacks targeting application logic — things traditional network firewalls cannot detect.",optionExplanations:["Network DDoS is mitigated by anti-DDoS services, not a WAF.","A WAF inspects HTTP traffic to block SQL injection, XSS, and CSRF attacks.","Endpoint malware is handled by antivirus/EDR, not a WAF.","Physical access controls are unrelated to a WAF's function."]},
  {id:373,domain:P,question:"What is the right to erasure (right to be forgotten) under GDPR?",options:["Right to access and review held data","Right to request data deletion","Right to delete another person's data","Right to object to automated decisions"],answer:1,explanation:"Article 17 GDPR allows individuals to request deletion of their personal data under specific circumstances, including withdrawal of consent.",optionExplanations:["Access rights (Article 15) let individuals view data; erasure lets them request deletion.","Article 17 lets individuals request deletion when processing is no longer justified.","Erasure only covers one's own data, not another person's.","Objecting to automated decisions is a separate right under Article 22."]},
  {id:374,domain:G,question:"What is salting in the context of password storage?",options:["Enforcing password complexity rules","Encrypting passwords with a shared key","Compressing the password database","Adding a unique random value before hashing"],answer:3,explanation:"Salts ensure identical passwords produce different hashes, defeating precomputed rainbow table attacks and making per-password cracking necessary.",optionExplanations:["Complexity rules are a policy control, not a hash-protection technique.","Salting works alongside hashing, not shared-key encryption.","Compression reduces storage size, unrelated to hash protection.","A salt adds unique randomness before hashing, defeating rainbow table attacks."]},
  {id:375,domain:O,question:"What is the purpose of security orchestration, automation, and response (SOAR)?",options:["A unified dashboard for all alerts","Continuous automated penetration testing","Automating and coordinating security tasks","Fully replacing human analysts"],answer:2,explanation:"SOAR platforms run playbooks to automatically triage alerts, enrich data, contain threats, and coordinate multi-tool response actions.",optionExplanations:["Unified dashboards are a SIEM feature; SOAR focuses on automated action.","Automated pen testing is a separate tool category, not SOAR's function.","SOAR automates repetitive tasks and orchestrates workflows across security tools.","SOAR augments analysts rather than replacing human judgment."]},
  {id:376,domain:T,question:"What is pretexting in social engineering?",options:["Threatening legal consequences directly","Setting up fake look-alike websites","Sending mass generic phishing emails","Fabricating a false identity"],answer:3,explanation:"Pretexting involves creating a believable false context (impersonating IT support, auditors, vendors) to make targets comply with requests.",optionExplanations:["Threats are intimidation tactics, not the fabricated-identity approach of pretexting.","Fake websites describe phishing/pharming, not building a false narrative directly.","Mass phishing lacks a tailored pretext; pretexting crafts a believable story.","Pretexting builds a false scenario, like impersonating IT or an auditor, to gain trust."]},
  {id:377,domain:A,question:"What is the purpose of a hardware security module (HSM)?",options:["Software-based full-disk encryption","Monitoring hardware temperatures","Physical locks for server racks","Tamper-resistant key storage device"],answer:3,explanation:"HSMs protect private keys by ensuring they never leave the hardware boundary, with tamper-evident mechanisms that destroy keys if tampering is detected.",optionExplanations:["Disk encryption may use keys; an HSM is where such keys are protected.","Temperature monitoring is an infrastructure function, not key protection.","Rack locks are physical access controls, not cryptographic key protection.","HSMs securely generate, store, and use keys with tamper-resistant hardware."]},
  {id:378,domain:O,question:"What is the mean time to detect (MTTD) security metric?",options:["Typical duration of a DDoS attack","Average time to complete training","Time from compromise to detection","Average time to remediate a vulnerability"],answer:2,explanation:"MTTD measures detection capability — lower is better. The industry average has historically been months, giving attackers time to cause significant damage.",optionExplanations:["DDoS duration varies by campaign; MTTD measures detection speed generally.","Training completion time is an HR/compliance metric, not detection speed.","MTTD measures the gap between initial compromise and its discovery.","Time to remediate is measured by MTTR, a separate metric from MTTD."]},
];
